import React, { useState, useEffect } from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import { Autoplay, EffectFade, Pagination } from "swiper/modules";
import "swiper/css";
import "swiper/css/effect-fade";
import "swiper/css/pagination";
import "./Home.css";
import { useParams } from "react-router-dom";
import Loading from "../../Pages/Loading/Loading";

function Home() {
  const { ProductId } = useParams();
  const productIndex = parseInt(ProductId, 10);

  const [loading, setLoading] = useState(true);
  const [slides, setSlides] = useState(null);

  useEffect(() => {
    const fetchSlides = async () => {
      try {
        const { HomeSliderDesktop, HomeSliderMobile } = await import("./../../Data/SliderImages");

        // Detect screen size & load only required images
        const isMobile = window.innerWidth <= 620;
        const selectedSlides = isMobile ? HomeSliderMobile : HomeSliderDesktop;

        setSlides(selectedSlides);
      } catch (error) {
        console.error("Error loading HomeSlider data:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchSlides();
  }, []);

  if (loading) {
    return <Loading />;
  }

  if (!slides || slides.length === 0) {
    return <div>No slides available</div>;
  }

  return (
    <Swiper
      className="home-swiper"
      autoplay={{ delay: 4000 }}
      effect="fade"
      pagination={{ clickable: true, type: "bullets" }}
      style={{
        "--swiper-pagination-bullet-active": "#FFFFFF",
        "--swiper-pagination-bullet-active-color": "#ff0000",
      }}
      modules={[EffectFade, Autoplay, Pagination]}
      loop={true}
    >
      {slides.map((slide, index) => (
        <SwiperSlide key={index} className="home-swiper-slide">
          <img src={slide.image} alt={slide.title} loading="lazy" />
        </SwiperSlide>
      ))}
    </Swiper>
  );
}

export default Home;






